import 'package:flutter/material.dart';import '../Models/sale_info.dart';extension CustomBuilder on List {  Widget listViewModel(      Widget Function(BuildContext, int) itemBuilder, bool? horizontal) {    horizontal ?? true;    return ListView.separated(      physics: const ClampingScrollPhysics(),      shrinkWrap: true,      scrollDirection: horizontal == true ? Axis.horizontal : Axis.vertical,      itemBuilder: (context, index) => itemBuilder(context, this[index]),      separatorBuilder: (context, index) => const SizedBox(        height: 10,        width: 10,      ),      itemCount: length,    );  }}String printName(List<String> name) {  String print = '';  for (int i = 0; i < name.length; i++) {    print = "$print${name[i]}";    if (i < name.length - 1) {      print = "$print\n";    }  }  return print;}String isFree(SaleInfo object) {  final String print ;  if (!object.isEbook!) {    return "Free";  } else {    print='${object.listPrice!.amount!.toInt()} ${object.listPrice!.currencyCode}';    return print.length > 8 ? print.substring(0, 8) : print.padRight(8);  }}